// ============================================================
// Extract & format the signal text from the Telegram message
// Handles both group messages and channel posts gracefully
// ============================================================

const item = $input.first().json;

// Channel posts come in as 'channel_post', group messages as 'message'
const message = item.message || item.channel_post || {};
const text = message.text || message.caption || '[No text content]';

// Extract metadata for logging
const chatTitle = message.chat?.title || 'Unknown Chat';
const chatType = message.chat?.type || 'unknown';
const messageDate = message.date
  ? new Date(message.date * 1000).toISOString()
  : new Date().toISOString();
const messageId = message.message_id || 'N/A';

// Build the analysis prompt with fixed portfolio context
const analysisPrompt = `Here is a new trading signal from my Broad Scanner v3.0: ${text}. Current portfolio has 11 positions with ~$56K exposure (heavy AI/tech bias). Analyze the signal for: fit with existing holdings, correlation risk, potential overlap, risk level, and give a short actionable recommendation (take it / skip / watch). Keep response concise.`;

return [{
  json: {
    signalText: text,
    analysisPrompt: analysisPrompt,
    chatTitle: chatTitle,
    chatType: chatType,
    messageDate: messageDate,
    messageId: messageId
  }
}];

// ============================================================
// Log the Grok analysis result alongside the original signal
// This node structures the output for easy review/export
// ============================================================

const input = $input.first().json;

// Get data from the Format Signal Prompt node
const signalData = $('Format Signal Prompt').first().json;

const logEntry = {
  timestamp: new Date().toISOString(),
  messageId: signalData.messageId,
  chatTitle: signalData.chatTitle,
  chatType: signalData.chatType,
  originalSignal: signalData.signalText,
  grokAnalysis: input.output || input.text || JSON.stringify(input),
  messageDate: signalData.messageDate,
  status: 'analyzed'
};

console.log('[Signal Analyzer] Processed signal:', logEntry.originalSignal?.substring(0, 80));
console.log('[Signal Analyzer] Grok says:', logEntry.grokAnalysis?.substring(0, 120));

return [{ json: logEntry }];
